"use client";

import { useEffect, useRef, useState, useCallback } from "react";
import { initTriangleDemo, type ShapeId } from "./triangle-demo";

type DemoState =
  | { status: "initial" }
  | { status: "loading" }
  | { status: "ready" }
  | { status: "error"; message: string }
  | { status: "unsupported"; message: string };

export function useWebGpuDemo(shapeId: ShapeId) {
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const titleRef = useRef<HTMLHeadingElement | null>(null);
  const [state, setState] = useState<DemoState>({ status: "initial" });
  const setShapeRef = useRef<((shapeId: ShapeId) => Promise<void>) | null>(null);
  const cleanupRef = useRef<(() => void) | null>(null);

  useEffect(() => {
    let cancelled = false;

    const run = async () => {
      if (!canvasRef.current) return;
      setState({ status: "loading" });

      const result = await initTriangleDemo(canvasRef.current, titleRef.current);

      if (cancelled) {
        if (result.status === "ready") result.cleanup();
        return;
      }

      if (result.status === "ready") {
        cleanupRef.current = result.cleanup;
        setShapeRef.current = result.setShape;
        void result.setShape(shapeId);
        setState({ status: "ready" });
      } else {
        setState({ status: result.status, message: result.message });
      }
    };

    void run();

    return () => {
      cancelled = true;
      cleanupRef.current?.();
      cleanupRef.current = null;
      setShapeRef.current = null;
    };
  }, []);

  useEffect(() => {
    void setShapeRef.current?.(shapeId);
  }, [shapeId]);

  const setShape = useCallback((id: ShapeId) => {
    void setShapeRef.current?.(id);
  }, []);

  return { canvasRef, titleRef, state, setShape };
}
