"use client";

import { useEffect, useState } from "react";
import dynamic from "next/dynamic";
import { motion } from "framer-motion";
import { AlertCircle, Copy, Download, Play, RotateCcw, Save, Share2, Wand2 } from "lucide-react";
import { useWorkspaceStore } from "@/lib/stores/workspace-store";
import { cn } from "@/lib/utils";

const Editor = dynamic(() => import("@monaco-editor/react"), { ssr: false });

export function CodeEditorPanel() {
  const { code, setCode, compileError, isRunning } = useWorkspaceStore();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  return (
    <div className="flex h-full flex-col overflow-hidden rounded-2xl border border-white/10 bg-[#0B0C15]/80 shadow-card">
      <div className="flex items-center justify-between border-b border-white/10 px-4 py-2">
        <div className="flex items-center gap-3">
          <span className="text-[10px] uppercase tracking-[0.3em] text-brand-subtle">WGSL Editor</span>
          <span className="text-xs text-slate-500">triangle.vert.wgsl</span>
        </div>
        <div className="flex items-center gap-1">
          <ToolbarButton icon={Play} label="Run" active={isRunning} />
          <ToolbarButton icon={RotateCcw} label="Reset" />
          <ToolbarButton icon={Wand2} label="Format" />
          <ToolbarButton icon={Copy} label="Copy" />
          <ToolbarButton icon={Download} label="Download" />
          <ToolbarButton icon={Share2} label="Share" />
          <ToolbarButton icon={Save} label="Save" />
        </div>
      </div>

      {compileError ? (
        <motion.div
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: "auto", opacity: 1 }}
          className="flex items-start gap-2 border-b border-rose-500/20 bg-rose-500/10 px-4 py-2 text-xs text-rose-200"
        >
          <AlertCircle className="mt-0.5 size-4 shrink-0" />
          <div className="min-w-0">
            <strong className="font-semibold">Shader compilation failed</strong>
            <p className="truncate text-rose-300/80">{compileError}</p>
          </div>
        </motion.div>
      ) : null}

      <div className="relative flex-1 overflow-hidden">
        {mounted ? (
          <Editor
            theme="vs-dark"
            defaultLanguage="wgsl"
            value={code || defaultVertexShader}
            onChange={(value) => setCode(value ?? "")}
            options={{
              minimap: { enabled: true, scale: 1 },
              fontSize: 13,
              fontFamily: "'JetBrains Mono', 'Fira Code', monospace",
              lineNumbers: "on",
              folding: true,
              wordWrap: "on",
              automaticLayout: true,
              scrollBeyondLastLine: false,
              renderWhitespace: "selection",
              padding: { top: 16 }
            }}
            className="h-full w-full"
          />
        ) : (
          <div className="flex h-full items-center justify-center text-xs text-slate-500">
            Loading Monaco editor…
          </div>
        )}
      </div>
    </div>
  );
}

function ToolbarButton({
  icon: Icon,
  label,
  active
}: {
  icon: typeof Play;
  label: string;
  active?: boolean;
}) {
  return (
    <button
      className={cn(
        "rounded-lg p-1.5 text-slate-400 transition-colors hover:bg-white/5 hover:text-slate-200",
        active && "text-brand"
      )}
      aria-label={label}
      title={label}
    >
      <Icon className="size-4" />
    </button>
  );
}

const defaultVertexShader = `@vertex
fn main(
  @builtin(vertex_index) VertexIndex : u32
) -> @builtin(position) vec4f {
  var pos = array<vec2f, 3>(
    vec2f(0.0, 0.5),
    vec2f(-0.5, -0.5),
    vec2f(0.5, -0.5)
  );
  return vec4f(pos[VertexIndex], 0.0, 1.0);
}
`;
