"use client";

import { motion } from "framer-motion";
import { Download, Edit3, Eye, Sparkles } from "lucide-react";
import { useState } from "react";
import { cn } from "@/lib/utils";

const shaders = [
  { id: "gradient", name: "Gradient", tone: "from-cyan-400 to-blue-500" },
  { id: "rainbow", name: "Rainbow", tone: "from-rose-400 via-amber-400 to-emerald-400" },
  { id: "glass", name: "Glass", tone: "from-slate-200/40 to-slate-400/40" },
  { id: "fire", name: "Fire", tone: "from-orange-500 to-red-600" },
  { id: "water", name: "Water", tone: "from-cyan-500 to-blue-700" },
  { id: "noise", name: "Noise", tone: "from-slate-500 to-slate-700" },
  { id: "aurora", name: "Aurora", tone: "from-emerald-400 via-cyan-500 to-purple-500" },
  { id: "crt", name: "CRT", tone: "from-green-400 to-green-600" },
  { id: "pixelate", name: "Pixelation", tone: "from-indigo-400 to-purple-600" },
  { id: "bloom", name: "Bloom", tone: "from-yellow-300 to-orange-400" },
  { id: "outline", name: "Outline", tone: "from-white to-slate-300" },
  { id: "toon", name: "Toon", tone: "from-pink-400 to-rose-500" },
  { id: "hologram", name: "Hologram", tone: "from-cyan-300/50 to-purple-400/50" },
  { id: "metal", name: "Metal", tone: "from-slate-300 to-slate-500" },
  { id: "pbr", name: "PBR", tone: "from-amber-300 to-orange-500" }
];

export function ShaderPlaygroundPanel() {
  const [active, setActive] = useState(shaders[0].id);

  return (
    <div className="flex h-full flex-col overflow-hidden rounded-2xl border border-white/10 bg-[#0B0C15]/80 p-5 shadow-card">
      <div className="mb-4">
        <span className="text-[10px] uppercase tracking-[0.3em] text-brand-subtle">Shader Playground</span>
        <h2 className="mt-1 font-display text-lg font-semibold text-white">Shader Gallery</h2>
        <p className="text-xs text-slate-400">Preview, edit, and download example WGSL shaders.</p>
      </div>

      <div className="grid flex-1 grid-cols-2 gap-3 overflow-y-auto sm:grid-cols-3 lg:grid-cols-4">
        {shaders.map((shader) => (
          <motion.button
            key={shader.id}
            onClick={() => setActive(shader.id)}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            className={cn(
              "group relative flex flex-col overflow-hidden rounded-xl border text-left transition-all",
              active === shader.id ? "border-brand/50" : "border-white/10 hover:border-white/20"
            )}
          >
            <div className={cn("h-20 w-full bg-gradient-to-br", shader.tone)} />
            <div className="flex flex-1 flex-col justify-between p-3">
              <span className="text-xs font-semibold text-white">{shader.name}</span>
              <div className="mt-2 flex items-center gap-2 text-slate-400">
                <Eye className="size-3" />
                <Edit3 className="size-3" />
                <Download className="size-3" />
              </div>
            </div>
            {active === shader.id ? (
              <div className="absolute right-2 top-2 rounded-full bg-brand/20 p-1">
                <Sparkles className="size-3 text-brand" />
              </div>
            ) : null}
          </motion.button>
        ))}
      </div>
    </div>
  );
}
